  ('elementary-acfc4025-moex-00607', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-91a9a65e', 'sub-elementary-acfc4025-04', NULL, 'single_choice', '有關JFET之操作特性，下列敘述何者錯誤？', '["JFET發生通道長度調變時，通道有效長度會隨V 的增加而略為變長，造成I 略為增加 DS D", "JFET操作於三極體區（trioderegion）時，隨V 的增加，通道深度變窄，通道電阻變大 DS", "JFET進入飽和區（saturationregion）時，D極附近的通道會夾止，I 維持定值 D", "JFET進入飽和區後，其I 與V 會呈現非線性關係 D GS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "e75b2626ba04", "answer_pdf_sha1": "836531565423", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "電子學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
